    private void showPremiumDialog() {
        String viText = "🔧 CÁC LỆNH ADB CỐT LÕI\n\n1. ADB bằng cáp USB (1 lần duy nhất):\nadb shell pm grant com.manhmoc.edgebar android.permission.WRITE_SECURE_SETTINGS\n\n2. ADB bằng WiFi (App LADB / Termux):\npm grant com.manhmoc.edgebar android.permission.WRITE_SECURE_SETTINGS\n\n*(Lưu ý: ADB WiFi đòi hỏi thiết bị phải luôn bật Gỡ lỗi Không dây trong Tùy chọn nhà phát triển. Nếu khởi động lại máy có thể sẽ mất).\n\n" +
                "💡 KHÁC BIỆT MÀN CHÍNH VÀ MÀN KHOÁ\n\n- MÀN KHOÁ (Lockscreen): Chạy qua quyền Trợ Năng (Accessibility). Chống Tapjacking mạnh mẽ nhất, ưu tiên tuyệt đối nhưng bị giới hạn không gian.\n- MÀN CHÍNH (Homescreen): Chạy qua quyền Lớp Phủ (Draw Overlays). Tự do vẽ vời 100%, có thể chọc chéo tắt/bật trợ năng để ẩn thân mượt mà.\n\n" +
                "🚀 VỀ BẢN CẬP NHẬT NÀY:\nApp tích hợp 15 Quick Settings Tile tùy chỉnh (gọi Intent trực tiếp từ Status bar), 5 Macro để tắt/bật nhiều app trợ năng 1 lúc, và cướp link YTDLnis từ Clipboard tự động.";
        String enText = "🔧 CORE ADB COMMANDS\n\n1. USB ADB (One-time only):\nadb shell pm grant com.manhmoc.edgebar android.permission.WRITE_SECURE_SETTINGS\n\n2. Wireless ADB (via LADB / Termux):\npm grant com.manhmoc.edgebar android.permission.WRITE_SECURE_SETTINGS\n\n*(Note: Wireless ADB requires keeping Wireless Debugging enabled in Developer Options. Rebooting may disable it).\n\n" +
                "💡 LOCKSCREEN VS HOMESCREEN\n\n- LOCKSCREEN: Runs via Accessibility Service. Strongest Tapjacking protection, absolute priority but restricted bounds.\n- HOMESCREEN: Runs via Draw Overlays. 100% freedom to draw, can cross-toggle Accessibility to hide flawlessly.\n\n" +
                "🚀 ABOUT THIS UPDATE:\nIncludes 15 Custom Quick Settings Tiles (fire Intents from Status bar), 5 Macros to toggle multiple accessibility apps simultaneously, and auto-snatch YTDLnis links from Clipboard.";

        ScrollView sv = new ScrollView(this); sv.setPadding(50,50,50,50);
        TextView tv = new TextView(this); tv.setText(isVi ? viText : enText); tv.setTextColor(Color.WHITE); tv.setTextSize(15f); tv.setLineSpacing(0, 1.3f); sv.addView(tv);
        AlertDialog.Builder b = new AlertDialog.Builder(this, android.R.style.Theme_DeviceDefault_Dialog_Alert);
        b.setTitle("👑 PREMIUM ARCHITECT INFO").setView(sv).setPositiveButton("OK", null).show();
    }

    private void updateVisTabs() { btnEditLock.setBackground(getRounded(designTabState==0 ? "#00E5FF" : "#222222", 20f)); btnEditLock.setTextColor(designTabState==0 ? Color.BLACK : Color.WHITE); btnEditHome.setBackground(getRounded(designTabState==1 ? "#00E5FF" : "#222222", 20f)); btnEditHome.setTextColor(designTabState==1 ? Color.BLACK : Color.WHITE); btnEditAnim.setBackground(getRounded(designTabState==2 ? "#00E5FF" : "#222222", 20f)); btnEditAnim.setTextColor(designTabState==2 ? Color.BLACK : Color.WHITE); }
    private LinearLayout createDrawer(String title, View content) { LinearLayout container = new LinearLayout(this); container.setOrientation(LinearLayout.VERTICAL); container.setBackground(getRounded("#222222", 20f)); LinearLayout.LayoutParams clp = new LinearLayout.LayoutParams(-1,-2); clp.setMargins(0,0,0,20); container.setLayoutParams(clp); TextView header = new TextView(this); header.setText("▼ " + title); header.setTextColor(Color.parseColor("#00E5FF")); header.setPadding(30,30,30,30); header.setTextSize(16); content.setVisibility(View.GONE); header.setOnClickListener(v -> { boolean isClosed = content.getVisibility() == View.GONE; content.setVisibility(isClosed ? View.VISIBLE : View.GONE); header.setText((isClosed ? "▲ " : "▼ ") + title); header.setBackground(getRounded(isClosed ? "#333333" : "#222222", 20f)); }); container.addView(header); container.addView(content); return container; }
    private LinearLayout createComboDropdown(String title, String key, String[] items, int def) { LinearLayout l = new LinearLayout(this); l.setOrientation(LinearLayout.HORIZONTAL); l.setGravity(Gravity.CENTER_VERTICAL); l.setPadding(0,10,0,20); TextView tv = new TextView(this); tv.setText(title); tv.setTextColor(Color.parseColor("#E91E63")); tv.setLayoutParams(new LinearLayout.LayoutParams(0,-2,1f)); Spinner sp = createSpinner(); sp.setAdapter(new ArrayAdapter<>(this, android.R.layout.simple_spinner_dropdown_item, items)); sp.setSelection(prefs.getInt(key, def)); sp.setOnItemSelectedListener(new AdapterView.OnItemSelectedListener(){public void onItemSelected(AdapterView<?> p, View v, int pos, long id){prefs.edit().putInt(key,pos).apply();}public void onNothingSelected(AdapterView<?> p){}}); sp.setLayoutParams(new LinearLayout.LayoutParams(0,-2,1.2f)); l.addView(tv); l.addView(sp); return l; }

